import { useState, useEffect } from "react";
import "./styles/global.css";

// Pages
import HomePage from "./pages/HomePage";
import RecipeDetailPage from "./pages/RecipeDetailPage";

// Auth
import LoginPage from "./pages/auth/LoginPage";
import RegisterPage from "./pages/auth/RegisterPage";
import ForgotPasswordPage from "./pages/auth/ForgotPasswordPage";

// User
import UserDashboardPage from "./pages/user/UserDashboardPage";

// Chef
import ChefDashboardPage from "./pages/chef/ChefDashboardPage";

// Admin
import AdminDashboardPage from "./pages/admin/AdminDashboardPage";

// Components
import Navbar from "./components/Navbar";

/**
 * RecipeNest — Full Multi-Role App
 *
 * Pages:
 *  "home"             → Public landing + recipe grid
 *  "recipe-detail"    → Single recipe view
 *  "login"            → Login (routes to role dashboard on submit)
 *  "signup"           → Register (role picker: user / chef)
 *  "forgot-password"  → 4-step password reset flow
 *  "user-dashboard"   → Saved recipes, favorites
 *  "chef-dashboard"   → My creations, analytics
 *  "admin-dashboard"  → User mgmt, recipes, analytics, reports
 */
export default function App() {
  const [page, setPage] = useState("home");
  const [selectedRecipe, setSelectedRecipe] = useState(null);
  const [user, setUser] = useState(null);

  // Check for stored token on app load
  useEffect(() => {
    const token = localStorage.getItem("token");
    const storedUser = localStorage.getItem("user");

    if (token && storedUser) {
      try {
        setUser(JSON.parse(storedUser));
      } catch (error) {
        console.error("Error parsing stored user:", error);
        localStorage.removeItem("token");
        localStorage.removeItem("user");
      }
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setUser(null);
    setPage("home");
  };

  const render = () => {
    switch (page) {
      case "home":
        return (
          <>
            <Navbar setPage={setPage} user={user} onLogout={handleLogout} />
            <HomePage setPage={setPage} setSelectedRecipe={setSelectedRecipe} />
          </>
        );
      case "recipe-detail":
        return (
          <>
            <Navbar setPage={setPage} user={user} onLogout={handleLogout} />
            <RecipeDetailPage recipe={selectedRecipe} setPage={setPage} />
          </>
        );
      case "login":
        return <LoginPage setPage={setPage} setUser={setUser} />;
      case "signup":
        return <RegisterPage setPage={setPage} />;
      case "forgot-password":
        return <ForgotPasswordPage setPage={setPage} />;
      case "user-dashboard":
        return user && user.role === "user" ? (
          <>
            <Navbar setPage={setPage} user={user} onLogout={handleLogout} />
            <UserDashboardPage setPage={setPage} setSelectedRecipe={setSelectedRecipe} user={user} />
          </>
        ) : (
          setPage("login")
        );
      case "chef-dashboard":
        return user && user.role === "chef" ? (
          <>
            <Navbar setPage={setPage} user={user} onLogout={handleLogout} />
            <ChefDashboardPage setPage={setPage} setSelectedRecipe={setSelectedRecipe} user={user} />
          </>
        ) : (
          setPage("login")
        );
      case "admin-dashboard":
        return user && user.role === "admin" ? (
          <>
            <Navbar setPage={setPage} user={user} onLogout={handleLogout} />
            <AdminDashboardPage setPage={setPage} user={user} />
          </>
        ) : (
          setPage("login")
        );
      default:
        return (
          <>
            <Navbar setPage={setPage} user={user} onLogout={handleLogout} />
            <HomePage setPage={setPage} setSelectedRecipe={setSelectedRecipe} />
          </>
        );
    }
  };

  return <>{render()}</>;
}
